UPDATE df_task
SET deleted = 1,
    updated_by = #{updatedBy}
WHERE id = #{id}
  AND deleted = 0

mapper.select:
SELECT 
FROM df_task
WHERE task_name = #{taskName}
  AND deleted = 0

  AND id != #{excludeId}

LIMIT 1

SELECT 
FROM df_task
WHERE task_code = #{taskCode}
  AND deleted = 0

  AND id != #{excludeId}

LIMIT 1

SELECT COUNT(1) FROM df_task WHERE deleted = 0
AND task_name LIKE CONCAT('%', #{taskName}, '%')
AND task_code LIKE CONCAT('%', #{taskCode}, '%')
AND status = #{status}
AND category_id = #{categoryId}

SELECT 
FROM df_task
WHERE deleted = 0

  AND task_name LIKE CONCAT('%', #{query.taskName}, '%')


  AND task_code LIKE CONCAT('%', #{query.taskCode}, '%')


  AND status = #{query.status}


  AND category_id = #{query.categoryId}

ORDER BY updated_at DESC, id DESC
LIMIT #{offset}, #{pageSize}
